/**
 * capstone-green.test.mjs — L-capstone: Durable Hybrid-Recall Agent Memory (GREEN)
 *
 * Proves all capstone behaviors live:
 *
 *   T1: Process A writes 5 episodes atomically; Process B reads them cross-process;
 *       hybrid recall ranks target id=3 #1 (FTS ranks id=4 first, VEC ranks id=5 first).
 *
 *   T2: STRICT table rejects wrong-typed write (SQLITE_CONSTRAINT_DATATYPE, errcode=3091).
 *
 *   T3: updated_at trigger fires on UPDATE (column set to strftime NOW()).
 *
 *   T4: EXPLAIN QUERY PLAN for JSON1 metadata filter uses SEARCH USING INDEX.
 *
 *   T5: Online Backup API (better-sqlite3 .backup()) yields integrity_check=ok
 *       and reproduces hybrid recall. Plain cp of live WAL DB is torn (misses WAL rows).
 *
 *   T6: 2nd concurrent writer hits SQLITE_BUSY (errcode=5), then succeeds
 *       after busy_timeout.
 *
 * All assertions are against real SQLite via real OS processes. No mocks.
 */

import { test } from 'node:test';
import assert from 'node:assert/strict';
import { execFileSync, spawn } from 'node:child_process';
import { existsSync, unlinkSync, writeFileSync } from 'node:fs';
import { fileURLToPath } from 'node:url';
import { dirname, join } from 'node:path';
import { DatabaseSync } from 'node:sqlite';

const __dirname = dirname(fileURLToPath(import.meta.url));

const DB_PATH     = join(__dirname, 'agent-memory.db');
const BACKUP_PATH = join(__dirname, 'agent-memory-backup.db');
const LOCK_FILE   = join(__dirname, '_concurrent.lock');
const DONE_FILE   = join(__dirname, '_concurrent.done');

function cleanupDb(base) {
  for (const s of ['', '-wal', '-shm']) {
    try { unlinkSync(base + s); } catch {}
  }
}

function cleanup() {
  cleanupDb(DB_PATH);
  cleanupDb(BACKUP_PATH);
  cleanupDb(DB_PATH.replace('.db', '-torn-copy.db'));
  for (const f of [LOCK_FILE, DONE_FILE]) { try { unlinkSync(f); } catch {} }
}

// ─── T1: Cross-process write + hybrid recall ──────────────────────────────────
test('Live behavioral test — Process A writes episodes; Process B recalls via hybrid RRF; target id=3 ranks #1', () => {
  cleanup();

  // ── Process A: writer ─────────────────────────────────────────────────────
  console.log('[T1] spawning process A (writer)...');
  const writerOut = execFileSync(
    process.execPath,
    [join(__dirname, 'process-a-writer.mjs'), DB_PATH],
    { encoding: 'utf8', stderr: 'pipe' }
  );
  console.log('[T1] Process A output:');
  writerOut.trim().split('\n').forEach(l => console.log('  ', l));

  assert.ok(existsSync(DB_PATH), 'DB file must exist on disk after process A exits');

  // Parse process A summary
  const summaryMatch = writerOut.match(/SUMMARY: episodes=(\d+) vec_rows=(\d+)/);
  assert.ok(summaryMatch, 'Process A must output SUMMARY line');
  const [, episodeCount, vecCount] = summaryMatch;
  assert.strictEqual(parseInt(episodeCount), 5, 'Process A must write 5 episodes');
  assert.strictEqual(parseInt(vecCount), 5, 'Process A must write 5 vec rows');

  // Verify STRICT rejection was captured by process A
  const strictMatch = writerOut.match(/STRICT_REJECTION_MSG: (.+)/);
  assert.ok(strictMatch, 'Process A must log STRICT_REJECTION_MSG');
  const strictMsg = strictMatch[1].trim();
  console.log('[T1] STRICT rejection:', strictMsg);
  // SQLite STRICT INT column rejects TEXT: "cannot store TEXT value in INT column"
  assert.ok(
    strictMsg.toLowerCase().includes('text') ||
    strictMsg.toLowerCase().includes('datatype') ||
    strictMsg.toLowerCase().includes('constraint') ||
    strictMsg.toLowerCase().includes('cannot store'),
    `STRICT rejection message must mention type/datatype: "${strictMsg}"`
  );

  // Verify EXPLAIN QUERY PLAN uses index
  const planMatch = writerOut.match(/PLAN: (.+)/);
  assert.ok(planMatch, 'Process A must log PLAN line');
  const planStr = planMatch[1].trim();
  console.log('[T1] EXPLAIN QUERY PLAN:', planStr);
  assert.ok(
    planStr.includes('USING INDEX') || planStr.includes('idx_episodes_meta_tag'),
    `EXPLAIN QUERY PLAN should show index usage, got: "${planStr}"`
  );

  // ── Process B: recall ─────────────────────────────────────────────────────
  console.log('[T1] spawning process B (recall)...');
  const recallOut = execFileSync(
    process.execPath,
    [join(__dirname, 'process-b-recall.mjs'), DB_PATH],
    { encoding: 'utf8', stderr: 'pipe' }
  );
  console.log('[T1] Process B output:');
  recallOut.trim().split('\n').forEach(l => console.log('  ', l));

  // Parse process B result line
  const resultMatch = recallOut.match(/RESULT: count=(\d+) hybrid_top=(\d+) fts_top=(\d+) vec_top=(\d+)/);
  assert.ok(resultMatch, 'Process B must output RESULT line');
  const [, pBCount, hybridTop, ftsTop, vecTop] = resultMatch.map(Number);

  // Cross-process durability: B sees all 5 episodes written by A
  assert.strictEqual(pBCount, 5, `Process B must see 5 episodes from Process A's write (got ${pBCount})`);

  // Hybrid recall: target id=3 must rank #1
  assert.strictEqual(hybridTop, 3,
    `Hybrid recall must rank target id=3 first, got id=${hybridTop}`
  );

  // FTS-only: id=4 must win (not the target)
  assert.strictEqual(ftsTop, 4,
    `FTS-only must rank id=4 "Memory Recall Buffer" first, got id=${ftsTop}`
  );
  assert.notEqual(ftsTop, 3,
    `FTS-only must NOT rank target id=3 first (proves FTS alone is insufficient)`
  );

  // VEC-only: id=5 must win (not the target)
  assert.strictEqual(vecTop, 5,
    `VEC-only must rank id=5 "Agent Context Store" first, got id=${vecTop}`
  );
  assert.notEqual(vecTop, 3,
    `VEC-only must NOT rank target id=3 first (proves VEC alone is insufficient)`
  );

  console.log('[T1] PASS: cross-process write + hybrid recall proved');
  console.log(`[T1]   FTS winner: id=${ftsTop} | VEC winner: id=${vecTop} | HYBRID winner: id=${hybridTop} (target=3)`);
});

