async function readNdjsonStream(resp) {
  const events = [];
  const rawLines = [];
  const reader = resp.body.getReader();
  const decoder = new TextDecoder();
  let buf = "";

  const TERMINAL_TYPES = new Set([
    "session.waiting",
    "session.completed",
    "session.failed",
    "turn.failed",
  ]);

  const timeoutId = setTimeout(() => {
    reader.cancel("stream timeout").catch(() => {});
  }, STREAM_TIMEOUT_MS);

  try {
    while (true) {
      let result;
      try {
        result = await reader.read();
      } catch {
        break;
      }
      const { done, value } = result;
      if (done) break;
      buf += decoder.decode(value, { stream: true });
      const lines = buf.split("\n");
      buf = lines.pop();
      for (const line of lines) {
        const trimmed = line.trim();
        if (!trimmed) continue;
        rawLines.push(trimmed);
        try {
          const ev = JSON.parse(trimmed);
          events.push(ev);
          if (TERMINAL_TYPES.has(ev.type)) {
            reader.cancel("terminal event received").catch(() => {});
            if (buf.trim()) {
              rawLines.push(buf.trim());
              try { events.push(JSON.parse(buf.trim())); } catch {}
            }
            clearTimeout(timeoutId);
            return { events, rawLines };
          }
        } catch {
          console.warn("  [WARN] Non-JSON line:", trimmed);
        }
      }
    }
  } finally {
    clearTimeout(timeoutId);
  }

  if (buf.trim()) {
    rawLines.push(buf.trim());
    try { events.push(JSON.parse(buf.trim())); } catch {}
  }
  return { events, rawLines };
}

