### source/auth-middleware.mjs
```mjs
/**
 * auth-middleware.mjs
 *
 * Reusable verifyToken() function that enforces the secure defaults jose
 * does NOT apply by default:
 *   - Required algorithms allowlist (prevents algorithm confusion attacks)
 *   - Required audience claim (aud) validation
 *   - Required issuer claim (iss) validation
 *   - exp and nbf are enforced by jose automatically when present
 *
 * Usage:
 *   import { verifyToken, createVerifier } from './auth-middleware.mjs';
 *
 *   // One-off verification
 *   const { payload } = await verifyToken(jwt, publicKey, {
 *     audience: 'my-api',
 *     issuer: 'https://auth.example.com',
 *     algorithms: ['ES256'],
 *   });
 *
 *   // Create a pre-configured verifier (middleware factory pattern)
 *   const verifier = createVerifier(publicKey, {
 *     audience: 'my-api',
 *     issuer: 'https://auth.example.com',
 *     algorithms: ['ES256'],
 *   });
 *   const { payload } = await verifier(jwt);
 */

import { jwtVerify } from 'jose';

/**
 * VerifyOptions: the secure defaults this middleware enforces.
 * All three fields are required — omitting any one is a configuration error.
 *
 * @typedef {Object} VerifyOptions
 * @property {string|string[]} audience - Required audience claim value(s)
 * @property {string}          issuer   - Required issuer claim value
 * @property {string[]}        algorithms - Allowed signing algorithms (e.g. ['ES256'])
 */

/**
 * verifyToken — secure JWT verification with enforced defaults.
 *
 * Wraps jwtVerify() and ensures audience, issuer, and algorithms are always
 * checked. Throws the native jose error classes on any violation:
 *   - JWSSignatureVerificationFailed  (tampered token)
 *   - JWTExpired                      (exp in the past)
 *   - JWTClaimValidationFailed        (wrong aud or iss)
 *   - JOSEAlgNotAllowed               (algorithm not in allowlist)
 *   - JWTClaimValidationFailed        (nbf in the future — err.claim === 'nbf')
 *
 * @param {string}     jwt      - The compact JWT string
 * @param {CryptoKey}  key      - The public key (or secret for HMAC)
 * @param {VerifyOptions} opts  - Required verification options
 * @returns {Promise<{payload: JWTPayload, protectedHeader: JoseHeader}>}
 */
export async function verifyToken(jwt, key, opts) {
  const { audience, issuer, algorithms } = opts;

  if (!audience) throw new Error('verifyToken: audience is required');
  if (!issuer) throw new Error('verifyToken: issuer is required');
  if (!algorithms || algorithms.length === 0) throw new Error('verifyToken: algorithms is required');

  return jwtVerify(jwt, key, { audience, issuer, algorithms });
}

/**
 * createVerifier — middleware factory that pre-binds key + options.
 * Returns a single-argument function: (jwt) => Promise<{payload, protectedHeader}>
 *
 * @param {CryptoKey}    key  - The public key (or secret for HMAC)
 * @param {VerifyOptions} opts - Required verification options (bound at creation time)
 * @returns {(jwt: string) => Promise<{payload: JWTPayload, protectedHeader: JoseHeader}>}
 */
export function createVerifier(key, opts) {
  return (jwt) => verifyToken(jwt, key, opts);
}

